<div class="card p-3"><h2 class="h5">Utilizadores</h2><div class="table-responsive"><table class="table table-sm align-middle"><thead><tr><th>ID</th><th>Nome</th><th>Email</th><th>Telefone</th><th>Estado</th><th>Criado em</th></tr></thead><tbody><?php foreach (($users ?? []) as $u): ?><tr><td>#<?= (int) $u['id'] ?></td><td><?= htmlspecialchars((string) ($u['name'] ?? '-')) ?></td><td><?= htmlspecialchars((string) ($u['email'] ?? '-')) ?></td><td><?= htmlspecialchars((string) ($u['phone'] ?? '-')) ?></td><td><?= !empty($u['is_active']) ? 'Activo' : 'Inactivo' ?></td><td><?= htmlspecialchars((string) ($u['created_at'] ?? '-')) ?></td></tr><?php endforeach; ?></tbody></table></div></div>
